tpl.sections.forEach((sec, i) => {
  checkPage(LINE_H * 2);
  pdf.setFont('times', 'bold');
  pdf.setFontSize(H2);
  writeText(`${i + 1}. ${sec}:`, MARGIN_X, CONTENT_W, LINE_H * 1.4);

  // ❌ removed underline
  y += 2;
  const content = sectionContent[sec] || '';
  const isCode = sec.toLowerCase().includes('code');
  if (isCode && content) {
    pdf.setFont('courier', 'normal');
    pdf.setFontSize(BASE - 1);
    const codeLines = pdf.splitTextToSize(content, CONTENT_W - 8);
    const blockH = codeLines.length * LINE_H * 0.95 + 6;
    checkPage(blockH);
    pdf.setFillColor(245, 245, 245);
    pdf.rect(MARGIN_X, y, CONTENT_W, blockH, 'F'); // no border

    y += 3;
    codeLines.forEach(line => {
      checkPage(LINE_H);
      pdf.text(line, MARGIN_X + 4, y);
      y += LINE_H;
    });
    y += 3;
  } else {
    pdf.setFont('helvetica', 'normal');
    writeText(content || '(no content)', MARGIN_X + 2, CONTENT_W - 4, LINE_H);
  }
  y += 4;
});

